function calculateEducationalValue(inputs) {
  const { historicalSignificance, interpretiveProgramQuality, physicalAccessibility, intellectualAccessibility, digitalResourcesQuality, curriculumAlignment, interactiveEngagementFeatures, staffExpertise, sitePreservationAuthenticity } = inputs;

  // Input validation and clamping to ensure values are within expected ranges
  const clamp = (value, min, max) => Math.max(min, Math.min(max, value || min));

  const hs = clamp(historicalSignificance, 1, 10);
  const ipq = clamp(interpretiveProgramQuality, 1, 10);
  const pa = clamp(physicalAccessibility, 1, 5);
  const ia = clamp(intellectualAccessibility, 1, 5);
  const dsq = clamp(digitalResourcesQuality, 1, 5);
  const ca = clamp(curriculumAlignment, 1, 10);
  const ief = clamp(interactiveEngagementFeatures, 1, 10);
  const se = clamp(staffExpertise, 1, 5);
  const spa = clamp(sitePreservationAuthenticity, 1, 10);

  // Step 1: Normalize all inputs to a 0-100 scale for consistent weighting
  const historicalSignificanceNorm = hs * 10;
  const interpretiveProgramQualityNorm = ipq * 10;
  const physicalAccessibilityNorm = pa * 20;
  const intellectualAccessibilityNorm = ia * 20;
  const digitalResourcesQualityNorm = dsq * 20;
  const curriculumAlignmentNorm = ca * 10;
  const interactiveEngagementFeaturesNorm = ief * 10;
  const staffExpertiseNorm = se * 20;
  const sitePreservationAuthenticityNorm = spa * 10;

  // Step 2: Calculate Sub-Scores (Curriculum Relevance, Visitor Engagement, Accessibility)

  // Curriculum Relevance Potential (direct mapping from normalized curriculum alignment)
  const curriculumRelevancePotential = curriculumAlignmentNorm;

  // Accessibility Score (weighted average of physical, intellectual, and digital access)
  let accessibilityScore = (
    physicalAccessibilityNorm * 0.40 +
    intellectualAccessibilityNorm * 0.40 +
    digitalResourcesQualityNorm * 0.20
  );
  accessibilityScore = Math.min(100, Math.max(0, accessibilityScore)); // Clamp 0-100

  // Visitor Engagement Potential (weighted average of program quality, interactive features, and digital resources)
  let visitorEngagementPotential = (
    interpretiveProgramQualityNorm * 0.40 + // Program quality itself is key to engagement
    interactiveEngagementFeaturesNorm * 0.40 + // Hands-on features
    digitalResourcesQualityNorm * 0.20 // Digital engagement resources
  );
  visitorEngagementPotential = Math.min(100, Math.max(0, visitorEngagementPotential)); // Clamp 0-100

  // Step 3: Calculate the Overall Educational Impact Score using weighted averages of all factors
  const overallEducationalImpactScore = (
    historicalSignificanceNorm * 0.20 +        // High weight for foundational significance
    curriculumRelevancePotential * 0.20 +      // High weight for educational applicability
    visitorEngagementPotential * 0.20 +        // High weight for direct learner interaction
    accessibilityScore * 0.15 +                // Important for equitable access to education
    interpretiveProgramQualityNorm * 0.10 +    // Core content delivery beyond pure engagement
    sitePreservationAuthenticityNorm * 0.10 +  // Authenticity and integrity are crucial for historical learning
    staffExpertiseNorm * 0.05                  // Quality of guidance enhances learning
  );
  const finalEducationalImpactScore = Math.min(100, Math.max(0, overallEducationalImpactScore)); // Clamp 0-100

  // Step 4: Determine Accessibility Grade based on the Accessibility Score
  let accessibilityGrade;
  if (accessibilityScore >= 90) accessibilityGrade = "A+";
  else if (accessibilityScore >= 85) accessibilityGrade = "A";
  else if (accessibilityScore >= 80) accessibilityGrade = "A-";
  else if (accessibilityScore >= 75) accessibilityGrade = "B+";
  else if (accessibilityScore >= 70) accessibilityGrade = "B";
  else if (accessibilityScore >= 65) accessibilityGrade = "B-";
  else if (accessibilityScore >= 60) accessibilityGrade = "C+";
  else if (accessibilityScore >= 55) accessibilityGrade = "C";
  else if (accessibilityScore >= 50) accessibilityGrade = "C-";
  else accessibilityGrade = "D";

  return {
    overallEducationalImpactScore: finalEducationalImpactScore,
    curriculumRelevancePotential: curriculumRelevancePotential,
    visitorEngagementPotential: visitorEngagementPotential,
    accessibilityGrade: accessibilityGrade
  };
}
